1	//! `RECEIVE` — synchronous receive.
2	//!
3	//! Translation of MINIX 3 `kernel/proc.c:977 mini_receive()`. Searches in
4	//! order: pending notifications (synthesized on the fly from the caller's
5	//! `priv.notify_pending` bitmap), then queued senders in `caller_q`. If
6	//! nothing matches, the caller blocks with `RTS_RECEIVING` and records
7	//! the source filter and user-buffer VA so a later [`mini_send`] can
8	//! deposit the message and unblock us.
9	
10	use core::sync::atomic::Ordering;
11	
12	use minix4_kernel_shared::ProcNr;
13	use minix4_kernel_shared::com::NR_SYS_PROCS;
14	use minix4_kernel_shared::endpoint::{ANY, Endpoint};
15	use minix4_kernel_shared::error::{EBADSRCDST, ELOCKED, ENOTREADY, OK};
16	use minix4_kernel_shared::ipc_const::RECEIVE;
17	
18	use crate::ipc::deadlock::deadlock_check;
19	use crate::ipc::notify::build_notify_message;
20	use crate::proc::flags::{
21	    MF_DELIVERMSG, MF_REPLY_PEND, RTS_RECEIVING, RTS_SENDING,
22	};
23	use crate::proc::priv_struct::IPC_MAP_CHUNKS;
24	use crate::proc::table::{N_PROC_SLOTS, proc_index};
25	use crate::proc::{Priv, Proc, sched};
26	
27	/// Blocking discipline for [`mini_receive`].
28	#[derive(Copy, Clone, Eq, PartialEq, Debug)]
29	pub enum RecvFlags {
30	    /// `RECEIVE` — block if no matching message is queued.
31	    Blocking,
32	    /// Non-blocking (no IPC primitive exposes this today, but the dispatch
33	    /// path passes it from the `RECEIVE` half of a SENDREC; symmetric to
34	    /// [`super::send::SendFlags::NonBlocking`]).
35	    #[allow(dead_code)]
36	    NonBlocking,
37	}
38	
39	/// `RECEIVE` primitive.
40	pub fn mini_receive(
41	    proc_table: &mut [Proc; N_PROC_SLOTS],
42	    priv_table: &mut [Priv; NR_SYS_PROCS],
43	    caller_nr: ProcNr,
44	    src_e: Endpoint,
45	    user_msg_va: u64,
46	    flags: RecvFlags,
47	) -> i32 {
48	    let Some(caller_idx) = proc_index(caller_nr) else {
49	        return EBADSRCDST;
50	    };
51	
52	    // Record buffer VA up-front. Even if we block here, a later deferred
53	    // SEND will find this and deposit the message at the right place when
54	    // the flush path runs.
55	    proc_table[caller_idx].deliver_msg_vir = user_msg_va;
56	
57	    // SENDREC mid-flight: SEND half blocked, RECEIVE half just kicked in.
58	    // Skip pending-message checks and proceed straight to "block on
59	    // receive". MINIX 3 proc.c:1010.
60	    let caller_rts = proc_table[caller_idx].rts_flags.load(Ordering::Relaxed);
61	    let in_mid_sendrec = caller_rts & RTS_SENDING != 0;
62	
63	    if !in_mid_sendrec {
64	        // 1. Pending notification?
65	        if let Some(sender_e) =
66	            take_pending_notification(proc_table, priv_table, caller_idx, src_e)
67	        {
68	            let caller = &mut proc_table[caller_idx];
69	            build_notify_message(caller, sender_e);
70	            caller.misc_flags |= MF_DELIVERMSG;
71	            return OK;
72	        }
73	
74	        // 2. (Skip pending async — `mini_senda` is an ENOSYS stub.)
75	
76	        // 3. Walk caller_q for a sender matching src_e (or ANY).
77	        if let Some(matched) = walk_caller_q(proc_table, caller_idx, src_e) {
78	            return matched;
79	        }
80	    }
81	
82	    // Nothing to deliver.
83	    if flags == RecvFlags::NonBlocking {
84	        return ENOTREADY;
85	    }
86	
87	    if deadlock_check(&*proc_table, RECEIVE, caller_nr, src_e) {
88	        return ELOCKED;
89	    }
90	
91	    let caller = &mut proc_table[caller_idx];
92	    caller.getfrom_e = src_e;
93	    // SAFETY: single-threaded SVC invariant; no other borrow into
94	    // `proc_table` is live.
95	    unsafe { sched::rts_set(caller, RTS_RECEIVING) };
96	    OK
97	}
98	
99	/// Look for the first pending notification matching `src_e` (or any, if
100	/// `src_e == ANY`) in `caller`'s `notify_pending` bitmap. Returns the
101	/// sender's endpoint and clears the bit on success.
102	fn take_pending_notification(
103	    proc_table: &[Proc; N_PROC_SLOTS],
104	    priv_table: &mut [Priv; NR_SYS_PROCS],
105	    caller_idx: usize,
106	    src_e: Endpoint,
107	) -> Option<Endpoint> {
108	    let Some(caller_priv_id) = proc_table[caller_idx].priv_id else {
109	        return None;
110	    };
111	    let caller_priv_idx = caller_priv_id.as_usize();
112	
113	    // Snapshot the caller's notify_pending bitmap so the lookup loop can
